const { ref, isVisible } = useIntersectionObserver({ triggerOnce: true });
const [displayValue, setDisplayValue] = useState(0);

useEffect(() => {
  if (isVisible) {
    let current = 0;
    const interval = setInterval(() => {
      current += proficiency / 12;
      setDisplayValue(Math.min(current, proficiency));
      if (current >= proficiency) clearInterval(interval);
    }, 50);
  }
}, [isVisible]);

return (
  <div ref={ref} className='mb-6'>
    <div className='flex items-center justify-between mb-2'>
      <span className='font-medium'>{name}</span>
      <span className='text-sm text-muted-foreground'>{Math.round(displayValue)}%</span>
    </div>
    <Progress value={displayValue} className='h-2' />
  </div>
);
